{
  "summary": "The extraction failed to meet the required accuracy. While the company, date, address, and total were correctly identified, the subtotal was missed, the tax field was populated with the subtotal value, and the line items were significantly under-counted due to merging multiple distinct items into single entries.",
  "failure_reasons": [
    "missing_subtotal",
    "incorrect_tax_value",
    "merged_line_items",
    "missing_line_items"
  ],
  "field_notes": {
    "subtotal": "The predicted subtotal is null.",
    "tax": "The predicted tax value ($24.24) is actually the subtotal.",
    "line_items": "The model merged several line items into single descriptions (e.g., combining 'Wonton or Egg Drop' with 'Mixed Dinner'). It also missed the 'Wonton Soup' item and had a slight discrepancy in the line total for the 'Juice Chinese Chop' item ($8.95 vs $8.99)."
  }
}
